option.value:
plugins {
    id 'java'
    id 'org.springframework.boot' version '4.0.6'
    id 'io.spring.dependency-management' version '1.1.7'
}

group = 'com.abd'
version = '0.0.1-SNAPSHOT'
description = 'interactive-calculator'

java {
    toolchain {
        languageVersion = JavaLanguageVersion.of(17)
    }
}

repositories {
    mavenCentral()
}

dependencies {
    implementation 'org.springframework.boot:spring-boot-starter'
    testImplementation 'org.springframework.boot:spring-boot-starter-test'
    testRuntimeOnly 'org.junit.platform:junit-platform-launcher'
}

tasks.named('test') {
    useJUnitPlatform()
}

plugins {
    id 'java'
    id 'application'
    id 'org.springframework.boot' version '4.0.6'
    id 'io.spring.dependency-management' version '1.1.7'
}

group = 'com.abd'
version = '0.0.1-SNAPSHOT'
description = 'interactive-calculator'

java {
    toolchain {
        languageVersion = JavaLanguageVersion.of(17)
    }
}

application {
    // Desktop entrypoint (Swing/JOptionPane). This lets you run the app without Spring.
    mainClass = 'com.abd.interactivecalculator.model.Calculator'
}

// Produce a runnable plain jar for the desktop entrypoint (no Spring Boot needed).
tasks.named('jar') {
    manifest {
        attributes('Main-Class': application.mainClass.get())
    }
}

repositories {
    mavenCentral()
}

dependencies {
    implementation 'org.springframework.boot:spring-boot-starter'

    // Optional compile-time annotations/metadata (improves IDE support; no runtime impact).
    compileOnly 'org.jspecify:jspecify:1.0.0'
    annotationProcessor 'org.springframework.boot:spring-boot-configuration-processor'

    testImplementation 'org.springframework.boot:spring-boot-starter-test'
    testRuntimeOnly 'org.junit.platform:junit-platform-launcher'
}

tasks.named('test') {
    useJUnitPlatform()
}

package com.abd.interactivecalculator;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

@SpringBootApplication
public class InteractiveCalculatorApplication {

    public static void main(String[] args) {
        SpringApplication.run(InteractiveCalculatorApplication.class, args);
    }

}

package com.abd.interactivecalculator;

import org.springframework.boot.builder.SpringApplicationBuilder;
import org.springframework.boot.autoconfigure.SpringBootApplication;

@SpringBootApplication
public class InteractiveCalculatorApplication {

    public static void main(String[] args) {
        // Swing/JOptionPane requires non-headless mode.
        new SpringApplicationBuilder(InteractiveCalculatorApplication.class)
                .headless(false)
                .run(args);
    }

}

package com.abd.interactivecalculator;

import com.abd.interactivecalculator.model.Calculator;
import com.abd.interactivecalculator.config.CalculatorStartupProperties;
import org.jspecify.annotations.NullMarked;
import org.springframework.boot.CommandLineRunner;
import org.springframework.context.annotation.Profile;
import org.springframework.stereotype.Component;

/**
 * Starts the interactive calculator dialogs when the Spring Boot app starts.
 *
 * <p>Enabled by default. Disable via: {@code calculator.startup.enabled=false}
 * (useful for tests).
 */
@Component
@Profile("!test")
@NullMarked
public class StartupRunner implements CommandLineRunner {

    private final CalculatorStartupProperties properties;

    public StartupRunner(CalculatorStartupProperties properties) {
        this.properties = properties;
    }

    @Override
    public void run(String... args) {
        if (!properties.isEnabled()) {
            return;
        }
        // Delegate to the existing Calculator main method which shows JOptionPane dialogs.
        Calculator.main(args);
    }
}

package com.abd.interactivecalculator.config;

import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.stereotype.Component;

/**
 * Configuration for the interactive startup behavior.
 */
@Component
@ConfigurationProperties(prefix = "calculator.startup")
public class CalculatorStartupProperties {

    /**
     * Whether to start the interactive calculator UI on application startup.
     */
    private boolean enabled = true;

    public boolean isEnabled() {
        return enabled;
    }

    public void setEnabled(boolean enabled) {
        this.enabled = enabled;
    }
}

